<?php $conn=new mysqli("127.0.0.1","root","","bookstore_db"); if($conn->connect_error){echo "CONNECTERROR: ".$conn->connect_error; exit(1);} $res=$conn->query("DESCRIBE products"); if(!$res){echo "ERROR: ".$conn->error; exit(1);} while($row=$res->fetch_assoc()){ echo $row["Field"]."|".$row["Type"]."|".$row["Null"]."|".$row["Key"]."|".$row["Default"]."|".$row["Extra"]."\n";} $res2=$conn->query("SELECT COUNT(*) AS c FROM products"); $r2=$res2->fetch_assoc(); echo "COUNT|".$r2["c"]."\n"; ?>
